def number_to_string_expression(n):
    if n == 0:
        return ""

    num_str = str(n)
    length = len(num_str)
    parts = []

    for i, digit in enumerate(num_str):
        if digit != '0':
            power_of_10 = 10 ** (length - i - 1)
            if power_of_10 == 1:
                parts.append(f"{digit}")
            else:
                parts.append(f"{digit}*{power_of_10}")

    return "+".join(parts)

