def can_obtain_by_substitution_cipher(string1, string2):
    if len(string1) != len(string2):
        return False

    map1_to_2 = {}
    map2_to_1 = {}

    for char1, char2 in zip(string1, string2):
        # Check if there's an existing mapping for char1
        if char1 in map1_to_2:
            # If the existing mapping doesn't match char2, return False
            if map1_to_2[char1] != char2:
                return False
        else:
            # Create a new mapping from char1 to char2
            map1_to_2[char1] = char2

        # Check if there's an existing mapping for char2
        if char2 in map2_to_1:
            # If the existing mapping doesn't match char1, return False
            if map2_to_1[char2] != char1:
                return False
        else:
            # Create a new mapping from char2 to char1
            map2_to_1[char2] = char1

    return True

