def alphabet_war(fight):
    # Initialize power values for each side
    left_power = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    right_power = {'m': 4, 'q': 3, 'd': 2, 'z': 1}

    # Convert the string to a list for easier manipulation
    fight_list = list(fight)

    # Neutralize letters adjacent to '*'
    for i in range(len(fight_list)):
        if fight_list[i] == '*':
            if i > 0:
                fight_list[i - 1] = '_'
            if i < len(fight_list) - 1:
                fight_list[i + 1] = '_'

    # Calculate the total power for each side
    left_total = 0
    right_total = 0

    for char in fight_list:
        if char in left_power:
            left_total += left_power[char]
        elif char in right_power:
            right_total += right_power[char]

    # Determine the result
    if left_total > right_total:
        return "Left side wins!"
    elif right_total > left_total:
        return "Right side wins!"
    else:
        return "Let's fight again!"

