def getAllPrimeFactors(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    if n == 2:
        return [2]
    factors = []
    divisor = 2
    while n >= divisor:
        while n % divisor == 0:
            factors.append(divisor)
            n //= divisor
        divisor += 1
    return factors

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, int) or n <= 0:
        return [[], []]
    if n == 1:
        return [[1], [1]]
    if n == 2:
        return [[2], [1]]
    all_factors = getAllPrimeFactors(n)
    unique_factors = []
    counts = []
    for factor in all_factors:
        if factor in unique_factors:
            counts[unique_factors.index(factor)] += 1
        else:
            unique_factors.append(factor)
            counts.append(1)
    return [unique_factors, counts]

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    if n == 2:
        return [2]
    unique_factors, counts = getUniquePrimeFactorsWithCount(n)
    products = [factor ** count for factor, count in zip(unique_factors, counts)]
    return products

