def transform_string(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    exceptions = {'c', 'o', 'd', 'e'}
    result = []

    for char in s:
        original_char = char
        if char in vowels:
            if char == 'e':
                char = chr(((ord(char) - ord('a') - 4) % 26) + ord('a'))
            else:
                char = chr(((ord(char) - ord('a') - 5) % 26) + ord('a'))
        elif char in exceptions:
            if char == 'c':
                char = chr(((ord(char) - ord('a') - 1) % 26) + ord('a'))
            elif char == 'o':
                char = chr(((ord(char) - ord('a') - 1) % 26) + ord('a'))
            elif char == 'd':
                char = chr(((ord(char) - ord('a') - 3) % 26) + ord('a'))
            elif char == 'e':
                char = chr(((ord(char) - ord('a') - 4) % 26) + ord('a'))
        else:
            char = chr(((ord(char) - ord('a') + 9) % 26) + ord('a'))

        if char in exceptions:
            char = original_char

        result.append(char)

    return ''.join(result)

