def replace_yellow_with_green(color):
    # Dictionary for HTML color name replacements
    yellow_to_green = {
        "gold": "ForestGreen",
        "khaki": "LimeGreen",
        "lemonchiffon": "PaleGreen",
        "lightgoldenrodyellow": "SpringGreen",
        "lightyellow": "MintCream",
        "palegoldenrod": "LightGreen",
        "yellow": "Lime"
    }

    # Check if the input is a hex code or a color name
    if color.startswith('#'):
        # Hex color code processing
        r = int(color[1:3], 16)
        g = int(color[3:5], 16)
        b = int(color[5:7], 16)

        # Check if the color is "yellow"
        if r > b and g > b:
            # Rearrange RGB values
            rgb = sorted([r, g, b])
            new_hex = f"#{rgb[0]:02X}{rgb[2]:02X}{rgb[1]:02X}"
            # Maintain the case of the input
            if color.islower():
                return new_hex.lower()
            else:
                return new_hex.upper()
        else:
            return color
    else:
        # HTML color name processing
        color_lower = color.lower()
        if color_lower in yellow_to_green:
            return yellow_to_green[color_lower]
        else:
            return color

