def sieve_of_eratosthenes(limit):
    is_prime = [True] * (limit + 1)
    p = 2
    while (p * p <= limit):
        if (is_prime[p] == True):
            for i in range(p * p, limit + 1, p):
                is_prime[i] = False
        p += 1
    prime_numbers = [p for p in range(2, limit + 1) if is_prime[p]]
    return prime_numbers

def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def sum_of_dominant_primes(a, b):
    # Generate a list of prime numbers up to a reasonable limit
    limit = 500000
    primes = sieve_of_eratosthenes(limit)

    # Determine prime positions
    prime_positions = [i for i in range(1, len(primes) + 1) if is_prime(i)]

    # Identify dominant primes
    dominant_primes = [primes[i - 1] for i in prime_positions if i <= len(primes)]

    # Filter and sum dominant primes within the range (a, b)
    dominant_primes_in_range = [p for p in dominant_primes if a <= p <= b]
    return sum(dominant_primes_in_range)

