    # Iterate over possible values of a
    for a in range(n + 1):
        b = n - a
        current_digit_sum = digit_sum(a) + digit_sum(b)
        if current_digit_sum > max_digit_sum:
            max_digit_sum = current_digit_sum

    return max_digit_sum

