    if len(vowel_list) > len(consonant_list):
        start_with_vowel = True
    elif len(consonant_list) > len(vowel_list):
        start_with_vowel = False
    else:
        start_with_vowel = True

    # Construct alternating string
    result = []
    v_idx, c_idx = 0, 0

    while v_idx < len(vowel_list) and c_idx < len(consonant_list):
        if start_with_vowel:
            result.append(vowel_list[v_idx])
            v_idx += 1
            start_with_vowel = False
        else:
            result.append(consonant_list[c_idx])
            c_idx += 1
            start_with_vowel = True

    # Append remaining characters
    if v_idx < len(vowel_list):
        result.append(vowel_list[v_idx])
    if c_idx < len(consonant_list):
