            if product * factors[i] <= n:
                total_ways += backtrack(product * factors[i], count + 1, i)  # Use i instead of 0 to avoid permutations

        return total_ways

    # Generate all factors of n
    factors = []
    for i in range(1, int(n**0.5) + 1):
        if n % i == 0:
            factors.append(i)
            if i != n // i:
                factors.append(n // i)

    factors.sort()

