def sum_of_squares(n):
    # Check if n is a perfect square
    if int(n**0.5) ** 2 == n:
        return 1

    # Check if the result is 2
    for i in range(1, int(n**0.5) + 1):
        if int((n - i*i)**0.5) ** 2 == (n - i*i):
            return 2

    # Check if the result is 4 using Legendre's three-square theorem
    original_n = n
    while n % 4 == 0:
        n //= 4
    if n % 8 == 7:
        return 4

    # If not 1, 2, or 4, then it must be 3
    return 3

