def countSubsequences(needle, haystack):
    dp = [0] * (len(needle) + 1)
    dp[0] = 1

    for char in haystack:
        for j in range(len(needle), 0, -1):
            if needle[j-1] == char:
                dp[j] += dp[j-1]

    return dp[len(needle)] % 100000000

