def mix(s1, s2):
    from collections import defaultdict

    # Initialize frequency counters
    freq_s1 = defaultdict(int)
    freq_s2 = defaultdict(int)

    # Count frequencies in s1
    for char in s1:
        if 'a' <= char <= 'z':
            freq_s1[char] += 1

    # Count frequencies in s2
    for char in s2:
        if 'a' <= char <= 'z':
            freq_s2[char] += 1

    # Determine maximum frequencies
    max_freq = []
    for char in 'abcdefghijklmnopqrstuvwxyz':
        count1 = freq_s1[char]
        count2 = freq_s2[char]
        if count1 > 1 or count2 > 1:
            if count1 > count2:
                max_freq.append((f"1:{char * count1}", count1))
            elif count2 > count1:
                max_freq.append((f"2:{char * count2}", count2))
            else:
                max_freq.append((f"=:{char * count1}", count1))

    # Sort substrings
    max_freq.sort(key=lambda x: (-x[1], x[0]))

    # Join and return
    return '/'.join([item[0] for item in max_freq])

