def same_structure_as(arr1, arr2):
    # Check if both are lists and have the same length
    if isinstance(arr1, list) and isinstance(arr2, list) and len(arr1) == len(arr2):
        # Iterate through elements of both lists
        for sub1, sub2 in zip(arr1, arr2):
            # If both elements are lists, recursively check their structure
            if isinstance(sub1, list) and isinstance(sub2, list):
                if not same_structure_as(sub1, sub2):
                    return False
            # If one is a list and the other is not, return False
            elif isinstance(sub1, list) != isinstance(sub2, list):
                return False
        # If all checks pass, return True
        return True
    # If they are not both lists or their lengths differ, return False
    return False

def differentiate(polynomial, x_value):
    import re

    # Split the polynomial into terms
    terms = re.findall(r'[+-]?\d*x(?:\^\d+)?|[+-]?\d+', polynomial)

    derivative_terms = []

    for term in terms:
        if 'x' in term:
            # Extract coefficient and exponent
            if '^' in term:
                match = re.match(r'([+-]?\d*)x\^(\d+)', term)
                coefficient, exponent = match.groups()
                exponent = int(exponent)
            else:
                match = re.match(r'([+-]?\d*)x', term)
                coefficient, exponent = match.groups()
                exponent = 1

            # Default coefficient to 1 or -1 if not specified
            if coefficient == '' or coefficient == '+':
                coefficient = 1
            elif coefficient == '-':
                coefficient = -1
            else:
                coefficient = int(coefficient)

            # Apply power rule: d/dx [ax^n] = n*ax^(n-1)
            if exponent > 0:
                new_coefficient = coefficient * exponent
                new_exponent = exponent - 1
                if new_exponent == 0:
                    derivative_terms.append(f'{new_coefficient}')
                elif new_exponent == 1:
                    derivative_terms.append(f'{new_coefficient}x')
                else:
                    derivative_terms.append(f'{new_coefficient}x^{new_exponent}')
        else:
            # Constant term, derivative is 0, so we skip it
            continue

    # Evaluate the derivative at the given x_value
    derivative_value = 0
    for term in derivative_terms:
        if 'x' in term:
            if '^' in term:
                coefficient, exponent = re.match(r'([+-]?\d+)x\^(\d+)', term).groups()
                exponent = int(exponent)
            else:
                coefficient, exponent = re.match(r'([+-]?\d+)x', term).groups()
                exponent = 1

            coefficient = int(coefficient)
            derivative_value += coefficient * (x_value ** exponent)
        else:
            derivative_value += int(term)

    return derivative_value

