def count_steps_to_stabilize(n, psychos):
    steps = 0
    while True:
        changes = False
        new_psychos = [psychos[0]]

        for i in range(1, len(psychos)):
            if psychos[i - 1] < psychos[i]:
                new_psychos.append(psychos[i])
            else:
                changes = True

        if not changes:
            break

        psychos = new_psychos
        steps += 1

    return steps

