def max_photos(n, a, b, T, orientations):
    # Calculate the time to view the first photo
    first_photo_time = 1 + (b if orientations[0] == 'w' else 0)

    # If we can't even view the first photo, return 0
    if first_photo_time > T:
        return 0

    # Initialize the maximum photos viewed
    max_photos_viewed = 1

    # Time left after viewing the first photo
    time_left = T - first_photo_time

    # Two pointers for exploring left and right
    right_time = [0] * n
    left_time = [0] * n

    # Calculate time to view photos moving right
    current_time = 0
    for i in range(1, n):
        current_time += a + 1 + (b if orientations[i] == 'w' else 0)
        right_time[i] = current_time

    # Calculate time to view photos moving left
    current_time = 0
    for i in range(1, n):
        current_time += a + 1 + (b if orientations[n - i] == 'w' else 0)
        left_time[i] = current_time

    # Check maximum photos by moving right
    for i in range(1, n):
        if right_time[i] <= time_left:
            max_photos_viewed = max(max_photos_viewed, i + 1)
        else:
            break

    # Check maximum photos by moving left
    for i in range(1, n):
        if left_time[i] <= time_left:
            max_photos_viewed = max(max_photos_viewed, i + 1)
        else:
            break

    # Check combinations of moving left and right
    for i in range(1, n):
        if right_time[i] <= time_left:
            remaining_time = time_left - right_time[i]
            for j in range(1, n - i):
                if left_time[j] <= remaining_time:
                    max_photos_viewed = max(max_photos_viewed, i + j + 1)
                else:
                    break

    for i in range(1, n):
        if left_time[i] <= time_left:
            remaining_time = time_left - left_time[i]
            for j in range(1, n - i):
                if right_time[j] <= remaining_time:
                    max_photos_viewed = max(max_photos_viewed, i + j + 1)
                else:
                    break

    return max_photos_viewed

