def max_apple_groups(n):
    paired = [False] * (n + 1)
    pairs = []

    # Iterate over numbers from n down to 2
    for i in range(n, 1, -1):
        if not paired[i]:
            # Try to pair with any number less than i
            for j in range(i - 1, 0, -1):
                if not paired[j] and gcd(i, j) > 1:
                    pairs.append((i, j))
                    paired[i] = True
                    paired[j] = True
                    break

    # Output the results
    print(len(pairs))
    for pair in pairs:
        print(pair[0], pair[1])

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

